import{_ as o,o as a,c as t,a4 as i}from"./chunks/framework.CDpUjPX_.js";const g=JSON.parse('{"title":"Auth — Fluxos e Decisoes","description":"","frontmatter":{},"headers":[],"relativePath":"api/auth.md","filePath":"api/auth.md"}'),d={name:"api/auth.md"};function c(l,e,r,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="auth-—-fluxos-e-decisoes" tabindex="-1">Auth — Fluxos e Decisoes <a class="header-anchor" href="#auth-—-fluxos-e-decisoes" aria-label="Permalink to &quot;Auth — Fluxos e Decisoes&quot;">​</a></h1><blockquote><p><strong>Endpoints completos:</strong> <a href="http://kubex.test/api/docs#/auth" target="_blank" rel="noreferrer">Swagger UI — Auth</a></p></blockquote><h2 id="fluxo-de-registro" tabindex="-1">Fluxo de Registro <a class="header-anchor" href="#fluxo-de-registro" aria-label="Permalink to &quot;Fluxo de Registro&quot;">​</a></h2><ol><li>User submits: <code>email</code>, <code>password</code>, <code>full_name</code>, <code>invite_code</code></li><li>reCAPTCHA v3 validado (score &gt;= 0.5, apenas prod)</li><li>Invite code verificado (ativo, nao usado)</li><li>Senha hasheada com bcrypt (via <code>asyncio.to_thread</code> — nao bloqueia event loop)</li><li>Email de verificacao enviado (token JWT)</li><li>Audit log: <code>&quot;register&quot;</code></li></ol><h2 id="fluxo-de-login" tabindex="-1">Fluxo de Login <a class="header-anchor" href="#fluxo-de-login" aria-label="Permalink to &quot;Fluxo de Login&quot;">​</a></h2><ol><li><code>POST /auth/login</code> com email + senha</li><li>bcrypt verify (async via <code>to_thread</code>)</li><li>Se 2FA ativo: retorna <strong>403</strong> com <code>requires_2fa=true</code></li><li>User faz <code>POST /auth/verify-2fa</code> com codigo TOTP</li><li><code>Set-Cookie</code>: <code>access_token</code> (15min) + <code>refresh_token</code> (7d)</li><li>Cookie domain: <code>.kubex.test</code> (dev) / <code>.kubex.com.br</code> (prod)</li><li>Audit log: <code>&quot;login&quot;</code></li></ol><h2 id="fluxo-2fa-totp" tabindex="-1">Fluxo 2FA (TOTP) <a class="header-anchor" href="#fluxo-2fa-totp" aria-label="Permalink to &quot;Fluxo 2FA (TOTP)&quot;">​</a></h2><ol><li><code>POST /auth/setup-2fa</code> — retorna <code>secret</code> + QR code base64 + provisioning URI</li><li>User escaneia QR no app (Google Authenticator, Authy)</li><li><code>POST /auth/verify-2fa</code> com codigo 6 digitos — ativa 2FA</li><li>Proximos logins exigem TOTP apos senha correta</li><li><code>POST /auth/disable-2fa</code> requer senha atual + audit log</li></ol><h2 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cookie</th><th>Duracao</th><th>Flags</th></tr></thead><tbody><tr><td><code>access_token</code></td><td>15 min</td><td><code>httpOnly</code>, <code>SameSite=Lax</code>, <code>Secure</code> (prod), <code>Path=/</code></td></tr><tr><td><code>refresh_token</code></td><td>7 dias</td><td><code>httpOnly</code>, <code>SameSite=Lax</code>, <code>Secure</code> (prod), <code>Path=/</code></td></tr></tbody></table><h2 id="seguranca" tabindex="-1">Seguranca <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Seguranca&quot;">​</a></h2><ul><li>Todas as acoes sensiveis geram <strong>audit log</strong> (login, register, logout, 2FA)</li><li>bcrypt via <code>asyncio.to_thread</code> (nao bloqueia event loop)</li><li>reCAPTCHA v3 em producao (desabilitado em dev)</li><li>Tokens JWT assinados com <code>SECRET_KEY</code></li><li>Cookies <code>httpOnly</code> — inacessiveis via JavaScript (XSS)</li><li><code>SameSite=Lax</code> — protecao CSRF</li><li>Invite code obrigatorio no registro</li></ul>',12)])])}const p=o(d,[["render",c]]);export{g as __pageData,p as default};
